const words = ["dog", "puppy", "spreadsheet"];
const resp = await client.embeddings.create({
  model: "text-embedding-3-small",
  input: words,
});
const vectors = Object.fromEntries(
  words.map((w, i) => [w, resp.data[i].embedding])
);

for (const [w, v] of Object.entries(vectors)) {
  console.log(`'${w}': ${v.length} dims, first 3 =`, v.slice(0, 3));
}
// 'dog': 1536 dims, first 3 = [0.0034..., -0.018..., ...]

function cosine(a, b) {
  let dot = 0, na = 0, nb = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    na += a[i] * a[i];
    nb += b[i] * b[i];
  }
  return dot / (Math.sqrt(na) * Math.sqrt(nb));
}

console.log("dog ~ puppy      :", cosine(vectors.dog, vectors.puppy).toFixed(4));
console.log("dog ~ spreadsheet:", cosine(vectors.dog, vectors.spreadsheet).toFixed(4));
// dog ~ puppy       : ~0.86
// dog ~ spreadsheet : ~0.18  -> meaning, not spelling, drives the score

