function keywordSearch(query, docs, k = 3) {
  const qWords = new Set(query.toLowerCase().split(" "));
  return docs
    .map((d) => {
      const dWords = new Set(d.toLowerCase().split(" "));
      const overlap = [...qWords].filter((w) => dWords.has(w)).length;
      return { overlap, d };
    })
    .sort((a, b) => b.overlap - a.overlap)
    .slice(0, k);
}

